Rules.InvariantScript:
// revert to prior document state if user leaves screen before saving
If(
    locJobDocumentSave = false,
    ClearCollect(
        colCdsJobDocuments,
        colJobDocumentsCancel
    )
);
// reset screen
UpdateContext(
    {
        locHideScreen: false,
        locJobDocumentSave: false,
        locShowSignatureCapture: false,
        locShowSignatureWarning: false
    }
)

//Set(locShowSignatureCapture, true); Set(locWhoseSignature, "Technician");
UpdateContext(
    {
        locShowSignatureCapture: true,
        locWhoseSignature: "Technician"
    }
)

With(
    {
        varType: "colCdsJobDocuments",
        varRecordRef: gblRecordCurrentDocument.'Job Document'
    },
    // change document completed status to 'yes'
    Patch(
        colCdsJobDocuments,
        LookUp(
            colCdsJobDocuments,
            'Job Document' = varRecordRef
        ),
        {
            DocumentDate: Today(),
            Completed: gblOptionSets.JobDocument.Completed.Yes
        }
    );
    // update job documents in the AUD records collection
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef= varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
//Save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobDocuments,
        "localCdsJobDocuments"
    )
);
// flag to save the document changes once screen is hidden
UpdateContext({locJobDocumentSave: true});
// next screen
Navigate('Documents Screen');

//Set(locShowSignatureWarning, false );Set(locShowSignatureCapture, false );
UpdateContext(
    {
        locShowSignatureWarning: false,
        locShowSignatureCapture: false
    }
)

With(
    {
        varType: "colCdsJobDocuments",
        varRecordRef: gblRecordCurrentDocument.'Job Document'
    },
    If(
        locWhoseSignature = "Homeowner 1",
        Patch(
            colCdsJobDocuments,
            LookUp(
                colCdsJobDocuments,
                'Job Document' = varRecordRef
            ),
            {
                'Homeowner Signature (1)': pen_SignDoc_Capture__Signature.Image,
                'Homeowner Signature Date (1)': Today()
            }
        ),
        locWhoseSignature = "Homeowner 2",
        Patch(
            colCdsJobDocuments,
            LookUp(
                colCdsJobDocuments,
                'Job Document' = varRecordRef
            ),
            {
                'Homeowner Signature (2)': pen_SignDoc_Capture__Signature.Image,
                'Homeowner Signature Date (2)': Today()
            }
        ),
        locWhoseSignature = "Technician",
        Patch(
            colCdsJobDocuments,
            LookUp(
                colCdsJobDocuments,
                'Job Document' = varRecordRef
            ),
            {
                'Technician Signature': pen_SignDoc_Capture__Signature.Image,
                'Technician Signature Date': Today()
            }
        )
    );
    // update job documents in the AUD records collection
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef= varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
// save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobDocuments,
        "localCdsJobDocuments"
    )
);
UpdateContext({locShowSignatureCapture: false});
Reset(pen_SignDoc_Capture__Signature);

If(
    locWhoseSignature = "Homeowner 1",
    Patch(
        colCdsJobDocuments,
        LookUp(
            colCdsJobDocuments,
            'Job Document' = gblRecordCurrentDocument.'Job Document'
        ),
        {
            'Homeowner Signature (1)': pen_SignDoc_Capture__Signature.Image,
            'Homeowner Signature Date (1)': Today()
        }
    ),
    locWhoseSignature = "Homeowner 2",
    Patch(
        colCdsJobDocuments,
        LookUp(
            colCdsJobDocuments,
            'Job Document' = gblRecordCurrentDocument.'Job Document'
        ),
        {
            'Homeowner Signature (2)': pen_SignDoc_Capture__Signature.Image,
            'Homeowner Signature Date (2)': Today()
        }
    ),
    locWhoseSignature = "Technician",
    Patch(
        colCdsJobDocuments,
        LookUp(
            colCdsJobDocuments,
            'Job Document' = gblRecordCurrentDocument.'Job Document'
        ),
        {
            'Technician Signature': pen_SignDoc_Capture__Signature.Image,
            'Technician Signature Date': Today()
        }
    )
);
With(
    {
        varType: "colCdsJobDocuments",
        varRecordRef: gblRecordCurrentDocument.'Job Document'
    },
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
        colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
// save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobDocuments,
        "localCdsJobDocuments"
    )
);
UpdateContext({locShowSignatureCapture: false});
Reset(pen_SignDoc_Capture__Signature);
